def range_summary(nums):
    if not nums:
        return ''

    nums.sort()
    ranges = []
    start, end = None, None

    for num in nums:
        if num == end + 1:
            end = num
        else:
            if start is not None:
                if start != end:
                    ranges.append(f'{start}-{end}')
                else:
                    ranges.append(str(start))
            start, end = num, num

    if start is not None:
        if start != end:
            ranges.append(f'{start}-{end}')
        else:
            ranges.append(str(start))

    return ','.join(ranges)
